```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define POOL_SIZE 8192     // 内存池大小
#define BLOCK_SIZE 32      // 内存块大小

// 内存池的结构体定义
typedef struct {
    int total_size;       // 内存池总大小
    int block_size;       // 内存块大小
    char *start;          // 内存池起始地址
    char *end;            // 内存池结束地址
    char *next;           // 下一个可分配内存块的地址
} MemPool;

// 初始化内存池
MemPool *MemPoolInit() {
    MemPool *p = (MemPool *) malloc(sizeof(MemPool));
    if (p == NULL) {
        return NULL;
    }
    p->total_size = POOL_SIZE;
    p->block_size = BLOCK_SIZE;
    p->start = (char *) malloc(POOL_SIZE);
    if (p->start == NULL) {
        free(p);
        return NULL;
    }
    p->end = p->start + p->total_size;
    p->next = p->start;
    return p;
}

// 分配内存
void *MemPoolAlloc(MemPool *p, int size) {
    if (p == NULL || size <= 0 || size > p->block_size) {
        return NULL;
    }
    if (p->next + size > p->end) {
        return NULL;    // 内存池已满，无法分配
    }
    char *p_mem = p->next;
    p->next += size;
    return (void *) p_mem;
}

// 释放内存池
void MemPoolFree(MemPool *p) {
    if (p != NULL && p->start != NULL) {
        free(p->start);
        free(p);
    }
}

int main() {
    MemPool *p_pool = MemPoolInit();
    if (p_pool == NULL) {
        printf("MemPoolInit failed!\n");
        return -1;
    }

    // 在内存池中分配内存
    char *p_mem1 = (char *) MemPoolAlloc(p_pool, 16);
    char *p_mem2 = (char *) MemPoolAlloc(p_pool, 32);
    char *p_mem3 = (char *) MemPoolAlloc(p_pool, 64);

    // 使用分配的内存
    strcpy(p_mem1, "hello1");
    strcpy(p_mem2, "world2");
    strcpy(p_mem3, "mem_pool3");
    printf("p_mem1=%s\n", p_mem1);
    printf("p_mem2=%s\n", p_mem2);
    printf("p_mem3=%s\n", p_mem3);

    // 释放内存池
    MemPoolFree(p_pool);
    return 0;
}
```

这段代码实现了一个最简单的内存池，它的内存块大小固定为32字节，内存池总大小为8192字节。在使用前可以根据需要更改这些参数。在代码中，我们使用malloc()函数来动态分配内存池的起始地址，然后通过MemPoolAlloc()函数向内存池申请内存，使用完后再通过MemPoolFree()函数释放整个内存池。

