该状态机有两个状态：开启状态和关闭状态，按下开关按钮可以切换状态。

```c
#include <stdio.h>

// 定义状态
typedef enum {
    STATE_OFF = 0,  // 关闭
    STATE_ON,       // 开启
    STATE_NUM       // 状态个数
} State;

// 定义事件
typedef enum {
    EVENT_SWITCH = 0 // 开关按钮被按下
} Event;

// 定义状态机结构体
typedef struct {
    State state;    // 当前状态
    void (*pStateFunc[STATE_NUM])(void);  // 状态处理函数数组
    Event event;    // 当前事件
} StateMachine;

// 状态切换处理函数
void SwitchProcess(StateMachine *p) {
    if (p->event == EVENT_SWITCH) {
        if (p->state == STATE_OFF) {
            printf("Switch ON!\n");
            p->state = STATE_ON;
        } else {
            printf("Switch OFF!\n");
            p->state = STATE_OFF;
        }
    }
}

// 初始化状态机
void StateMachineInit(StateMachine *p) {
    if (p != NULL) {
        p->state = STATE_OFF;
        p->pStateFunc[STATE_OFF] = NULL;
        p->pStateFunc[STATE_ON] = NULL;
        p->pStateFunc[STATE_OFF] = SwitchProcess;
        p->pStateFunc[STATE_ON] = SwitchProcess;
        p->event = EVENT_SWITCH;
    }
}

int main() {
    StateMachine sm;
    StateMachineInit(&sm);

    // 初始状态为关闭状态
    printf("Current state: STATE_OFF\n");

    // 按下开关按钮
    sm.event = EVENT_SWITCH;
    sm.pStateFunc[sm.state](&sm);

    // 打印当前状态
    if (sm.state == STATE_ON) {
        printf("Current state: STATE_ON\n");
    } else {
        printf("Current state: STATE_OFF\n");
    }
    return 0;
}
```

这段代码实现了一个简单的状态机，它有两个状态：开启和关闭，按下开关按钮可以切换状态。在代码中，我们使用枚举类型定义了状态和事件，使用函数指针数组实现了状态切换处理函数的调用，使用state保存当前状态。StateMachineInit()函数用于初始化状态机，然后在main()函数中按下开关按钮，调用状态切换处理函数，切换当前状态。最后根据当前状态打印输出。

