我们实现一个简单的跑步机控制有限状态机，包含三种状态：停止状态、开始状态和暂停状态，以及两种事件：开始运行和暂停。

```c
#include <stdio.h>
#include <stdlib.h>

// 状态
typedef enum {
    STOPPED = 0,
    RUNNING,
    PAUSED,
    STATES_TOTAL,
} State;

// 事件
typedef enum {
    START = 0,
    PAUSE,
    EVENTS_TOTAL,
} Event;

// 状态迁移函数指针
typedef void (*StateFunc)(void);

// 停止状态处理函数
void StoppedStateFunc(void) {
    printf("当前状态是：STOPPED\n");
}

// 开始状态处理函数
void RunningStateFunc(void) {
    printf("当前状态是：RUNNING\n");
}

// 暂停状态处理函数
void PausedStateFunc(void) {
    printf("当前状态是：PAUSED\n");
}

// 开始运行事件处理函数
void StartEventFunc(void) {
    printf("事件触发：START\n");
}

// 暂停事件处理函数
void PauseEventFunc(void) {
    printf("事件触发：PAUSE\n");
}

// 空状态处理函数
void EmptyFunc(void) {
    return;
}

// 状态机结构体
typedef struct {
    State state;            // 当前状态
    StateFunc state_funcs[STATES_TOTAL];    // 状态处理函数
    Event event;            // 当前事件
    StateFunc event_funcs[EVENTS_TOTAL];    // 事件处理函数
    State transitions[STATES_TOTAL][EVENTS_TOTAL];  // 状态迁移图
} StateMachine;

// 初始化状态机
void StateMachineInit(StateMachine *sm) {
    // 初始化状态
    sm->state = STOPPED;

    // 初始化状态处理函数
    sm->state_funcs[STOPPED] = StoppedStateFunc;
    sm->state_funcs[RUNNING] = RunningStateFunc;
    sm->state_funcs[PAUSED] = PausedStateFunc;

    // 初始化事件处理函数
    sm->event_funcs[START] = StartEventFunc;
    sm->event_funcs[PAUSE] = PauseEventFunc;

    // 初始化状态迁移图
    sm->transitions[STOPPED][START] = RUNNING;
    sm->transitions[RUNNING][PAUSE] = PAUSED;
    sm->transitions[PAUSED][PAUSE] = RUNNING;
    sm->transitions[PAUSED][START] = RUNNING;
}

// 处理当前事件
void ProcessEvent(StateMachine *sm) {
    // 调用事件处理函数
    sm->event_funcs[sm->event]();

    // 根据状态迁移图进行状态迁移
    sm->state = sm->transitions[sm->state][sm->event];
}

int main() {
    StateMachine sm;
    StateMachineInit(&sm);
    sm.event = START;
    ProcessEvent(&sm);
    sm.event = PAUSE;
    ProcessEvent(&sm);
    sm.event = START;
    ProcessEvent(&sm);
    sm.event = PAUSE;
    ProcessEvent(&sm);
    return 0;
}
```

在这段代码中，我们首先定义了状态和事件的枚举类型，然后定义了状态迁移函数指针，再定义函数指针类型的状态处理函数和事件处理函数。接下来定义状态机结构体，包括状态，状态处理函数，事件，事件处理函数和状态迁移图。然后在初始化状态机时分别初始化状态迁移函数，状态处理函数和事件处理函数。最后在main函数中调用两个事件，并且触发状态迁移过程。

状态迁移图是状态机的核心。在该实现中，我们使用的是一个二维数组来表示状态迁移图。数组的每个元素表示从一个状态通过一个事件迁移到另一个状态。如果没有明确的状态迁移，则状态迁移函数指针为空函数。在ProcessEvent()函数中，首先调用事件处理函数，然后从状态迁移图中查找对应的目标状态。

以上就是一个简单的有限状态机实现，它可以根据不同的事件做出不同的响应。
